package reporting;
import com.aventstack.extentreports.*;import com.aventstack.extentreports.reporter.ExtentSparkReporter;import config.ConfigReader;import constants.FrameworkConstants;import utils.DateTimeUtil;import java.nio.file.*;
public final class ExtentManager { private static ExtentReports extent; private ExtentManager(){} public static synchronized ExtentReports get(){ if(extent==null){ try{Files.createDirectories(Path.of(FrameworkConstants.REPORT_DIR));}catch(Exception ignored){} ExtentSparkReporter spark=new ExtentSparkReporter(FrameworkConstants.REPORT_DIR+"/ExtentReport-"+ DateTimeUtil.timestamp()+".html"); extent=new ExtentReports(); extent.attachReporter(spark); ConfigReader c=ConfigReader.getInstance(); extent.setSystemInfo("Environment",c.get("env")); extent.setSystemInfo("Browser",c.get("browser")); extent.setSystemInfo("Headless",c.get("headless")); } return extent; } public static synchronized void flush(){ if(extent!=null) extent.flush(); } }
